167→func findOrCreateTown() (string, error) {
168→	// Priority 1: GT_TOWN_ROOT env var (explicit user preference)
169→	if townRoot := os.Getenv("GT_TOWN_ROOT"); townRoot != "" {
170→		if isValidTown(townRoot) {
171→			return townRoot, nil
172→		}
173→	}
174→
175→	// Priority 2: Try to find from cwd (supports multiple town installations)
176→	if townRoot, err := workspace.FindFromCwd(); err == nil && townRoot != "" {
177→		return townRoot, nil
178→	}
179→
180→	// Priority 3: Fall back to well-known locations
181→	home, err := os.UserHomeDir()
182→	if err != nil {
183→		return "", err
184→	}
185→
186→	candidates := []string{
187→		filepath.Join(home, "gt"),
188→		filepath.Join(home, "gastown"),
189→	}
190→
191→	for _, path := range candidates {
192→		if isValidTown(path) {
193→			return path, nil
194→		}
195→	}
196→
197→	return "", fmt.Errorf("no Gas Town found - run 'gt install ~/gt' first")
198→}
